### 2. Update ApplicationDbContext

Edit /tmp/sv-4aa1e00ddbaf47cda5f52d602a39ec14/VetClinic/Data/ApplicationDbContext.cs to add DbSets and configure relationships:

```csharp
using Microsoft.AspNetCore.Identity.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore;
using VetClinic.Data.Models;

namespace VetClinic.Data;

public class ApplicationDbContext(DbContextOptions<ApplicationDbContext> options) : IdentityDbContext<ApplicationUser>(options)
{
    public DbSet<Owner> Owners => Set<Owner>();
    public DbSet<Pet> Pets => Set<Pet>();
    public DbSet<Treatment> Treatments => Set<Treatment>();
    public DbSet<Appointment> Appointments => Set<Appointment>();
    public DbSet<Invoice> Invoices => Set<Invoice>();
    public DbSet<InvoiceItem> InvoiceItems => Set<InvoiceItem>();
    public DbSet<Payment> Payments => Set<Payment>();

    protected override void OnModelCreating(ModelBuilder builder)
    {
        base.OnModelCreating(builder);

        builder.Entity<Owner>(e =>
        {
            e.HasMany(o => o.Pets).WithOne(p => p.Owner).HasForeignKey(p => p.OwnerId);
        });

        builder.Entity<Pet>(e =>
        {
            e.HasMany(p => p.Treatments).WithOne(t => t.Pet).HasForeignKey(t => t.PetId);
            e.HasMany(p => p.Appointments).WithOne(a => a.Pet).HasForeignKey(a => a.PetId);
            e.Property(p => p.Weight).HasColumnType("decimal(8,2)");
        });

        builder.Entity<Invoice>(e =>
        {
            e.HasOne(i => i.Owner).WithMany().HasForeignKey(i => i.OwnerId);
            e.HasOne(i => i.Appointment).WithMany().HasForeignKey(i => i.AppointmentId);
            e.HasMany(i => i.Items).WithOne(item => item.Invoice).HasForeignKey(item => item.InvoiceId);
            e.HasMany(i => i.Payments).WithOne(p => p.Invoice).HasForeignKey(p => p.InvoiceId);
            e.Property(i => i.TotalAmount).HasColumnType("decimal(10,2)");
        });

        builder.Entity<InvoiceItem>(e =>
        {
            e.Property(i => i.UnitPrice).HasColumnType("decimal(10,2)");
        });

        builder.Entity<Payment>(e =>
        {
            e.Property(p => p.Amount).HasColumnType("decimal(10,2)");
        });
    }
}
```

### 3. Delete template pages
Delete these files:
- /tmp/sv-4aa1e00ddbaf47cda5f52d602a39ec14/VetClinic/Components/Pages/Counter.razor
- /tmp/sv-4aa1e00ddbaf47cda5f52d602a39ec14/VetClinic/Components/Pages/Weather.razor
- /tmp/sv-4aa1e00ddbaf47cda5f52d602a39ec14/VetClinic/Components/Pages/Auth.razor

### 4. Update Home.razor

Replace /tmp/sv-4aa1e00ddbaf47cda5f52d602a39ec14/VetClinic/Components/Pages/Home.razor with a dashboard:

```razor
@page "/"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@attribute [Authorize]
@inject ApplicationDbContext Db

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>Clinic Dashboard</h1>

<div class="row mt-4">
    <div class="col-md-3">
        <div class="card text-bg-primary mb-3">
            <div class="card-body">
                <h5 class="card-title">Patients</h5>
                <p class="card-text display-6">@petCount</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-success mb-3">
            <div class="card-body">
                <h5 class="card-title">Today's Appointments</h5>
                <p class="card-text display-6">@todayAppointments</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-warning mb-3">
            <div class="card-body">
                <h5 class="card-title">Pending Invoices</h5>
                <p class="card-text display-6">@pendingInvoices</p>
            </div>
        </div>
    </div>
    <div class="col-md-3">
        <div class="card text-bg-info mb-3">
            <div class="card-body">
                <h5 class="card-title">Owners</h5>
                <p class="card-text display-6">@ownerCount</p>
            </div>
        </div>
    </div>
</div>

<div class="row mt-3">
    <div class="col-md-6">
        <h4>Upcoming Appointments</h4>
        @if (upcomingAppointments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Time</th><th>Pet</th><th>Reason</th><th>Vet</th></tr></thead>
                <tbody>
                    @foreach (var apt in upcomingAppointments)
                    {
                        <tr>
                            <td>@apt.StartTime.ToString("g")</td>
                            <td>@apt.Pet.Name</td>
                            <td>@apt.Reason</td>
                            <td>@apt.VetName</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No upcoming appointments.</p>
        }
    </div>
    <div class="col-md-6">
        <h4>Recent Treatments</h4>
        @if (recentTreatments.Any())
        {
            <table class="table table-striped">
                <thead><tr><th>Date</th><th>Pet</th><th>Description</th></tr></thead>
                <tbody>
                    @foreach (var t in recentTreatments)
                    {
                        <tr>
                            <td>@t.Date.ToString("d")</td>
                            <td>@t.Pet.Name</td>
                            <td>@t.Description</td>
                        </tr>
                    }
                </tbody>
            </table>
        }
        else
        {
            <p class="text-muted">No recent treatments.</p>
        }
    </div>
</div>

@code {
    private int petCount;
    private int ownerCount;
    private int todayAppointments;
    private int pendingInvoices;
    private List<Appointment> upcomingAppointments = new();
    private List<Treatment> recentTreatments = new();

    protected override async Task OnInitializedAsync()
    {
        var today = DateTime.UtcNow.Date;
        petCount = await Db.Pets.CountAsync();
        ownerCount = await Db.Owners.CountAsync();
        todayAppointments = await Db.Appointments
            .CountAsync(a => a.StartTime.Date == today && a.Status == AppointmentStatus.Scheduled);
        pendingInvoices = await Db.Invoices
            .CountAsync(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.Overdue);
        upcomingAppointments = await Db.Appointments
            .Include(a => a.Pet)
            .Where(a => a.StartTime >= DateTime.UtcNow && a.Status == AppointmentStatus.Scheduled)
            .OrderBy(a => a.StartTime)
            .Take(5)
            .ToListAsync();
        recentTreatments = await Db.Treatments
            .Include(t => t.Pet)
            .OrderByDescending(t => t.Date)
            .Take(5)
            .ToListAsync();
    }
