                <dt class="col-sm-3">Owner</dt><dd class="col-sm-9">@appointment.Pet.Owner.FirstName @appointment.Pet.Owner.LastName (@appointment.Pet.Owner.Phone)</dd>
            </dl>
        </div>
    </div>

    @if (appointment.Status == AppointmentStatus.Scheduled)
    {
        <h4>Reschedule</h4>
        <div class="row mb-3">
            <div class="col-md-3">
                <label class="form-label">New Date</label>
                <input type="date" class="form-control" @bind="rescheduleDate" />
            </div>
            <div class="col-md-3">
                <label class="form-label">New Time</label>
                <select class="form-select" @bind="rescheduleHour">
                    @for (int h = 8; h <= 17; h++)
                    {
                        <option value="@h">@($"{h:D2}:00")</option>
                    }
                </select>
            </div>
            <div class="col-md-3 d-flex align-items-end">
                <button class="btn btn-warning" @onclick="Reschedule">Reschedule</button>
            </div>
        </div>

        @if (rescheduleConflict is not null)
        {
            <div class="alert alert-warning">@rescheduleConflict</div>
        }

        <hr />
        <button class="btn btn-success me-2" @onclick="Complete">Mark Completed</button>
        <button class="btn btn-danger" @onclick="Cancel">Cancel Appointment</button>
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private Appointment? appointment;
    private DateTime rescheduleDate = DateTime.Today.AddDays(1);
    private int rescheduleHour = 9;
    private string? rescheduleConflict;

    protected override async Task OnInitializedAsync()
    {
        appointment = await Db.Appointments
            .Include(a => a.Pet).ThenInclude(p => p.Owner)
            .FirstOrDefaultAsync(a => a.Id == Id);
        if (appointment is not null)
        {
            rescheduleDate = appointment.StartTime.Date;
            rescheduleHour = appointment.StartTime.Hour;
        }
    }

    private async Task Reschedule()
    {
        if (appointment is null) return;
        var duration = appointment.EndTime - appointment.StartTime;
        var newStart = rescheduleDate.Date.AddHours(rescheduleHour);
        var newEnd = newStart.Add(duration);

        var conflict = await Db.Appointments.AnyAsync(a =>
            a.Id != Id &&
            a.Status == AppointmentStatus.Scheduled &&
            a.VetName == appointment.VetName &&
            a.StartTime < newEnd &&
            a.EndTime > newStart);

        if (conflict)
        {
            rescheduleConflict = "Conflict: vet is already booked at this time.";
            return;
        }

        appointment.StartTime = newStart;
        appointment.EndTime = newEnd;
        await Db.SaveChangesAsync();
        rescheduleConflict = null;
        StateHasChanged();
    }

    private async Task Complete()
    {
        if (appointment is null) return;
        appointment.Status = AppointmentStatus.Completed;
        await Db.SaveChangesAsync();
        StateHasChanged();
    }

    private async Task Cancel()
    {
        if (appointment is null) return;
        appointment.Status = AppointmentStatus.Cancelled;
        await Db.SaveChangesAsync();
        StateHasChanged();
    }

    private string GetBadgeClass() => appointment?.Status switch
    {
        AppointmentStatus.Scheduled => "bg-primary",
        AppointmentStatus.Completed => "bg-success",
        AppointmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
