    private List<Invoice>? invoices;
    private string filterStatus = string.Empty;
    private string searchTerm = string.Empty;

    protected override async Task OnInitializedAsync() => await LoadInvoices();

    private async Task LoadInvoices()
    {
        var query = Db.Invoices.Include(i => i.Owner).Include(i => i.Payments).AsQueryable();

        if (!string.IsNullOrEmpty(filterStatus) && Enum.TryParse<InvoiceStatus>(filterStatus, out var status))
            query = query.Where(i => i.Status == status);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(i => i.Owner.FirstName.ToLower().Contains(term) || i.Owner.LastName.ToLower().Contains(term));
        }

        invoices = await query.OrderByDescending(i => i.IssuedDate).ToListAsync();
    }

    private string GetBadgeClass(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.PartiallyPaid => "bg-info",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}
