        if (totalPaid >= invoice.TotalAmount)
            invoice.Status = InvoiceStatus.Paid;
        else
            invoice.Status = InvoiceStatus.PartiallyPaid;

        await Db.SaveChangesAsync();
        newPayment = new() { Amount = invoice.TotalAmount - totalPaid };
        StateHasChanged();
    }

