@page "/patients"
@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@attribute [Authorize]
@inject ApplicationDbContext Db
@inject NavigationManager Nav

<PageTitle>Patients - VetClinic</PageTitle>

<h1>Patients</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <input type="text" class="form-control" placeholder="Search by pet or owner name..."
               @bind="searchTerm" @bind:event="oninput" @bind:after="Search" />
    </div>
    <div class="col-md-6 text-end">
        <button class="btn btn-primary" @onclick='() => Nav.NavigateTo("/patients/new")'>
            <span class="bi bi-plus"></span> Register New Patient
        </button>
    </div>
</div>

@if (pets is null)
{
    <p>Loading...</p>
}
else if (!pets.Any())
{
    <p class="text-muted">No patients found.</p>
}
else
{
    <table class="table table-hover">
        <thead>
            <tr><th>Name</th><th>Species</th><th>Breed</th><th>Owner</th><th>Actions</th></tr>
        </thead>
        <tbody>
            @foreach (var pet in pets)
            {
                <tr>
                    <td>@pet.Name</td>
                    <td>@pet.Species</td>
                    <td>@pet.Breed</td>
                    <td>@pet.Owner.FirstName @pet.Owner.LastName</td>
                    <td>
                        <button class="btn btn-sm btn-outline-primary" @onclick="() => Nav.NavigateTo($@"/patients/{pet.Id}")">View</button>
                        <button class="btn btn-sm btn-outline-secondary" @onclick="() => Nav.NavigateTo($@"/patients/{pet.Id}/edit")">Edit</button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Pet>? pets;
    private string searchTerm = string.Empty;

    protected override async Task OnInitializedAsync() => await Search();

    private async Task Search()
    {
        var query = Db.Pets.Include(p => p.Owner).AsQueryable();
        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.ToLower();
            query = query.Where(p =>
                p.Name.ToLower().Contains(term) ||
                p.Owner.FirstName.ToLower().Contains(term) ||
                p.Owner.LastName.ToLower().Contains(term));
        }
        pets = await query.OrderBy(p => p.Name).ToListAsync();
    }
}

