@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@attribute [Authorize]
@inject ApplicationDbContext Db
@inject NavigationManager Nav

<PageTitle>Register Patient - VetClinic</PageTitle>

<h1>Register New Patient</h1>

<EditForm Model="model" OnValidSubmit="Save" FormName="registerPet">
    <DataAnnotationsValidator />
    <ValidationSummary />

    <h4>Owner Information</h4>
    <div class="row mb-3">
        <div class="col-md-6">
            <label class="form-label">Existing Owner</label>
            <select class="form-select" @bind="selectedOwnerId">
                <option value="0">-- New Owner --</option>
                @foreach (var owner in owners)
                {
                    <option value="@owner.Id">@owner.FirstName @owner.LastName</option>
                }
            </select>
        </div>
    </div>

    @if (selectedOwnerId == 0)
    {
        <div class="row mb-3">
            <div class="col-md-4">
                <label class="form-label">First Name</label>
                <InputText class="form-control" @bind-Value="ownerModel.FirstName" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Last Name</label>
                <InputText class="form-control" @bind-Value="ownerModel.LastName" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Phone</label>
                <InputText class="form-control" @bind-Value="ownerModel.Phone" />
            </div>
        </div>
        <div class="row mb-3">
