                }
            </InputSelect>
        </div>
        <div class="col-md-6">
            <label class="form-label">Veterinarian</label>
            <InputText class="form-control" @bind-Value="model.VetName" placeholder="Dr. ..." />
        </div>
    </div>
    <div class="row mb-3">
        <div class="col-md-4">
            <label class="form-label">Date</label>
            <InputDate class="form-control" @bind-Value="appointmentDate" />
        </div>
        <div class="col-md-4">
            <label class="form-label">Start Time</label>
            <InputSelect class="form-select" @bind-Value="startHour">
                @for (int h = 8; h <= 17; h++)
                {
                    <option value="@h">@($"{h:D2}:00")</option>
                }
            </InputSelect>
        </div>
        <div class="col-md-4">
            <label class="form-label">Duration (minutes)</label>
            <InputSelect class="form-select" @bind-Value="durationMinutes">
                <option value="30">30</option>
                <option value="60">60</option>
                <option value="90">90</option>
            </InputSelect>
        </div>
    </div>
    <div class="row mb-3">
        <div class="col-md-6">
            <label class="form-label">Reason</label>
            <InputText class="form-control" @bind-Value="model.Reason" />
        </div>
        <div class="col-md-6">
            <label class="form-label">Notes</label>
            <InputText class="form-control" @bind-Value="model.Notes" />
        </div>
    </div>

    @if (conflictMessage is not null)
    {
        <div class="alert alert-warning">@conflictMessage</div>
    }

    <button type="submit" class="btn btn-primary">Schedule</button>
    <button type="button" class="btn btn-secondary" @onclick='() => Nav.NavigateTo("/appointments")'>Cancel</button>
</EditForm>

@code {
    private Appointment model = new();
    private List<Pet> pets = new();
    private DateTime appointmentDate = DateTime.Today.AddDays(1);
    private int startHour = 9;
    private int durationMinutes = 30;
    private string? conflictMessage;

    [SupplyParameterFromQuery] public int? PetId { get; set; }

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        if (PetId.HasValue)
            model.PetId = PetId.Value;
    }

    private async Task Save()
    {
        model.StartTime = appointmentDate.Date.AddHours(startHour);
        model.EndTime = model.StartTime.AddMinutes(durationMinutes);

        var conflict = await Db.Appointments.AnyAsync(a =>
            a.Status == AppointmentStatus.Scheduled &&
            a.VetName == model.VetName &&
            a.StartTime < model.EndTime &&
            a.EndTime > model.StartTime);

        if (conflict)
        {
            conflictMessage = "This vet already has an appointment during this time slot.";
            return;
        }

        Db.Appointments.Add(model);
        await Db.SaveChangesAsync();
        Nav.NavigateTo("/appointments");
    }
}

