@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@attribute [Authorize]
@inject ApplicationDbContext Db
@inject NavigationManager Nav

<PageTitle>Appointments - VetClinic</PageTitle>

<h1>Appointments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <div class="input-group">
            <button class="btn btn-outline-secondary" @onclick="PreviousWeek">&laquo; Prev</button>
            <input type="date" class="form-control" @bind="currentDate" @bind:after="LoadAppointments" />
            <button class="btn btn-outline-secondary" @onclick="NextWeek">Next &raquo;</button>
        </div>
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="filterStatus" @bind:after="LoadAppointments">
            <option value="">All Statuses</option>
            <option value="Scheduled">Scheduled</option>
            <option value="Completed">Completed</option>
            <option value="Cancelled">Cancelled</option>
        </select>
    </div>
    <div class="col-md-4 text-end">
        <button class="btn btn-primary" @onclick='() => Nav.NavigateTo("/appointments/new")'>New Appointment</button>
    </div>
</div>

<div class="row">
    @for (int d = 0; d < 7; d++)
    {
        var day = currentDate.AddDays(d);
        var dayAppointments = appointments.Where(a => a.StartTime.Date == day.Date).OrderBy(a => a.StartTime).ToList();
        var slotsAvailable = 8 - dayAppointments.Count(a => a.Status == AppointmentStatus.Scheduled);

        <div class="col">
            <div class="card @(day.Date == DateTime.Today ? "border-primary" : "")">
                <div class="card-header text-center">
                    <strong>@day.ToString("ddd")</strong><br />@day.ToString("MMM d")
                    <br /><span class="badge @(slotsAvailable > 3 ? "bg-success" : slotsAvailable > 0 ? "bg-warning" : "bg-danger")">@slotsAvailable slots</span>
                </div>
                <div class="card-body p-1" style="min-height: 200px; font-size: 0.85rem;">
                    @foreach (var apt in dayAppointments)
                    {
                        <div class="border rounded p-1 mb-1 @GetStatusClass(apt.Status)" role="button"
                             @onclick="() => Nav.NavigateTo($@"/appointments/{apt.Id}")">
                            <strong>@apt.StartTime.ToString("HH:mm")</strong> @apt.Pet.Name<br />
                            <small>@apt.Reason</small>
                        </div>
                    }
                </div>
            </div>
        </div>
    }
</div>

@code {
    private DateTime currentDate = DateTime.Today;
    private string filterStatus = string.Empty;
    private List<Appointment> appointments = new();

    protected override async Task OnInitializedAsync() => await LoadAppointments();

    private async Task LoadAppointments()
    {
        var weekEnd = currentDate.AddDays(7);
        var query = Db.Appointments.Include(a => a.Pet)
            .Where(a => a.StartTime.Date >= currentDate.Date && a.StartTime.Date < weekEnd);

        if (!string.IsNullOrEmpty(filterStatus) && Enum.TryParse<AppointmentStatus>(filterStatus, out var status))
            query = query.Where(a => a.Status == status);

        appointments = await query.OrderBy(a => a.StartTime).ToListAsync();
    }

    private void PreviousWeek() { currentDate = currentDate.AddDays(-7); _ = LoadAppointments(); }
    private void NextWeek() { currentDate = currentDate.AddDays(7); _ = LoadAppointments(); }

    private string GetStatusClass(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "bg-light",
        AppointmentStatus.Completed => "bg-success-subtle",
        AppointmentStatus.Cancelled => "bg-danger-subtle text-decoration-line-through",
        _ => ""
    };
}

