@code {
    private Appointment model = new();
    private List<Pet> pets = new();
    private DateTime appointmentDate = DateTime.Today.AddDays(1);
    private int startHour = 9;
    private int durationMinutes = 30;
    private string? conflictMessage;

    [SupplyParameterFromQuery] public int? PetId { get; set; }

    protected override async Task OnInitializedAsync()
    {
        pets = await Db.Pets.Include(p => p.Owner).OrderBy(p => p.Name).ToListAsync();
        if (PetId.HasValue)
            model.PetId = PetId.Value;
    }

    private async Task Save()
    {
        model.StartTime = appointmentDate.Date.AddHours(startHour);
        model.EndTime = model.StartTime.AddMinutes(durationMinutes);

        var conflict = await Db.Appointments.AnyAsync(a =>
            a.Status == AppointmentStatus.Scheduled &&
            a.VetName == model.VetName &&
            a.StartTime < model.EndTime &&
            a.EndTime > model.StartTime);

        if (conflict)
        {
            conflictMessage = "This vet already has an appointment during this time slot.";
            return;
        }

        Db.Appointments.Add(model);
        await Db.SaveChangesAsync();
        Nav.NavigateTo("/appointments");
    }
}

