@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@attribute [Authorize]
@inject ApplicationDbContext Db
@inject NavigationManager Nav

<PageTitle>New Invoice - VetClinic</PageTitle>

<h1>Create Invoice</h1>

<EditForm Model="invoice" OnValidSubmit="Save" FormName="createInvoice">
    <DataAnnotationsValidator />

    <div class="row mb-3">
        <div class="col-md-6">
            <label class="form-label">Owner</label>
            <InputSelect class="form-select" @bind-Value="invoice.OwnerId">
                <option value="0">Select owner...</option>
                @foreach (var owner in owners)
                {
                    <option value="@owner.Id">@owner.FirstName @owner.LastName</option>
                }
            </InputSelect>
        </div>
        <div class="col-md-3">
            <label class="form-label">Issue Date</label>
            <InputDate class="form-control" @bind-Value="invoice.IssuedDate" />
        </div>
        <div class="col-md-3">
            <label class="form-label">Due Date</label>
            <InputDate class="form-control" @bind-Value="invoice.DueDate" />
        </div>
    </div>

    <h4>Line Items</h4>
    <table class="table">
        <thead><tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Total</th><th></th></tr></thead>
        <tbody>
            @for (int i = 0; i < items.Count; i++)
            {
                var idx = i;
                <tr>
                    <td><input class="form-control" @bind="items[idx].Description" /></td>
                    <td><input type="number" class="form-control" style="width:80px" @bind="items[idx].Quantity" /></td>
                    <td><input type="number" step="0.01" class="form-control" style="width:120px" @bind="items[idx].UnitPrice" /></td>
                    <td>@((items[idx].Quantity * items[idx].UnitPrice).ToString("C"))</td>
                    <td><button type="button" class="btn btn-sm btn-danger" @onclick="() => items.RemoveAt(idx)">&#x00d7;</button></td>
                </tr>
            }
        </tbody>
    </table>
    <button type="button" class="btn btn-sm btn-outline-secondary mb-3" @onclick="AddItem">+ Add Item</button>

    <div class="row mb-3">
        <div class="col-md-6">
            <label class="form-label">Notes</label>
            <InputTextArea class="form-control" @bind-Value="invoice.Notes" />
        </div>
        <div class="col-md-6 text-end">
            <h4>Total: @items.Sum(i => i.Quantity * i.UnitPrice).ToString("C")</h4>
        </div>
    </div>

    <button type="submit" class="btn btn-primary">Create Invoice</button>
    <button type="button" class="btn btn-secondary" @onclick='() => Nav.NavigateTo("/billing")'>Cancel</button>
</EditForm>

@code {
    private Invoice invoice = new() { IssuedDate = DateTime.UtcNow, DueDate = DateTime.UtcNow.AddDays(30) };
    private List<InvoiceItem> items = new() { new InvoiceItem() };
    private List<Owner> owners = new();

    protected override async Task OnInitializedAsync()
    {
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void AddItem() => items.Add(new InvoiceItem());

    private async Task Save()
    {
        invoice.TotalAmount = items.Sum(i => i.Quantity * i.UnitPrice);
        invoice.Items = items;
        Db.Invoices.Add(invoice);
        await Db.SaveChangesAsync();
        Nav.NavigateTo($"/billing/{invoice.Id}");
    }
}

