@using Microsoft.AspNetCore.Authorization
@using Microsoft.EntityFrameworkCore
@using VetClinic.Data
@using VetClinic.Data.Models
@attribute [Authorize]
@inject ApplicationDbContext Db
@inject NavigationManager Nav

<PageTitle>Invoice Details - VetClinic</PageTitle>

@if (invoice is null)
{
    <p>Loading...</p>
}
else
{
    <h1>Invoice #@invoice.Id</h1>
    <p class="text-muted">Owner: @invoice.Owner.FirstName @invoice.Owner.LastName | Issued: @invoice.IssuedDate.ToString("d") | Due: @invoice.DueDate.ToString("d")</p>
    <span class="badge @GetBadgeClass()">@invoice.Status</span>

    <h4 class="mt-4">Items</h4>
    <table class="table">
        <thead><tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Total</th></tr></thead>
        <tbody>
            @foreach (var item in invoice.Items)
            {
                <tr>
                    <td>@item.Description</td>
                    <td>@item.Quantity</td>
                    <td>@item.UnitPrice.ToString("C")</td>
                    <td>@((item.Quantity * item.UnitPrice).ToString("C"))</td>
                </tr>
            }
        </tbody>
        <tfoot>
            <tr><td colspan="3" class="text-end"><strong>Total</strong></td><td><strong>@invoice.TotalAmount.ToString("C")</strong></td></tr>
            <tr><td colspan="3" class="text-end">Paid</td><td>@totalPaid.ToString("C")</td></tr>
            <tr><td colspan="3" class="text-end"><strong>Balance Due</strong></td><td><strong>@((invoice.TotalAmount - totalPaid).ToString("C"))</strong></td></tr>
        </tfoot>
    </table>

    <h4>Payment History</h4>
    @if (invoice.Payments.Any())
    {
        <table class="table table-sm">
            <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr></thead>
            <tbody>
                @foreach (var p in invoice.Payments.OrderByDescending(p => p.PaidDate))
                {
                    <tr>
                        <td>@p.PaidDate.ToString("g")</td>
                        <td>@p.Amount.ToString("C")</td>
                        <td>@p.Method</td>
                        <td>@p.Reference</td>
                    </tr>
                }
            </tbody>
        </table>
    }
    else
    {
        <p class="text-muted">No payments recorded.</p>
    }

    @if (invoice.Status != InvoiceStatus.Paid)
    {
        <h4>Record Payment</h4>
        <EditForm Model="newPayment" OnValidSubmit="ProcessPayment" FormName="processPayment">
            <div class="row mb-3">
                <div class="col-md-3">
                    <label class="form-label">Amount</label>
                    <InputNumber class="form-control" @bind-Value="newPayment.Amount" />
                </div>
                <div class="col-md-3">
                    <label class="form-label">Method</label>
                    <InputSelect class="form-select" @bind-Value="newPayment.Method">
                        @foreach (var method in Enum.GetValues<PaymentMethod>())
                        {
                            <option value="@method">@method</option>
                        }
                    </InputSelect>
                </div>
                <div class="col-md-3">
                    <label class="form-label">Reference</label>
                    <InputText class="form-control" @bind-Value="newPayment.Reference" />
                </div>
                <div class="col-md-3 d-flex align-items-end">
                    <button type="submit" class="btn btn-success">Record Payment</button>
                </div>
            </div>
        </EditForm>
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private Payment newPayment = new();
    private decimal totalPaid;

    protected override async Task OnInitializedAsync() => await LoadInvoice();

    private async Task LoadInvoice()
    {
        invoice = await Db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == Id);

        if (invoice is not null)
        {
            totalPaid = invoice.Payments.Sum(p => p.Amount);
            newPayment.Amount = invoice.TotalAmount - totalPaid;
        }
    }

    private async Task ProcessPayment()
    {
        if (invoice is null) return;

        newPayment.InvoiceId = Id;
        newPayment.PaidDate = DateTime.UtcNow;
        Db.Payments.Add(newPayment);

        totalPaid += newPayment.Amount;
        if (totalPaid >= invoice.TotalAmount)
            invoice.Status = InvoiceStatus.Paid;
        else
            invoice.Status = InvoiceStatus.PartiallyPaid;

        await Db.SaveChangesAsync();
        newPayment = new() { Amount = invoice.TotalAmount - totalPaid };
        StateHasChanged();
    }

    private string GetBadgeClass() => invoice?.Status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.PartiallyPaid => "bg-info",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}

