    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private Payment newPayment = new();
    private decimal totalPaid;

    protected override async Task OnInitializedAsync() => await LoadInvoice();

    private async Task LoadInvoice()
    {
        invoice = await Db.Invoices
            .Include(i => i.Owner)
            .Include(i => i.Items)
            .Include(i => i.Payments)
            .FirstOrDefaultAsync(i => i.Id == Id);

        if (invoice is not null)
        {
            totalPaid = invoice.Payments.Sum(p => p.Amount);
            newPayment.Amount = invoice.TotalAmount - totalPaid;
        }
    }

    private async Task ProcessPayment()
    {
        if (invoice is null) return;

        newPayment.InvoiceId = Id;
        newPayment.PaidDate = DateTime.UtcNow;
        Db.Payments.Add(newPayment);

        totalPaid += newPayment.Amount;
        if (totalPaid >= invoice.TotalAmount)
            invoice.Status = InvoiceStatus.Paid;
        else
            invoice.Status = InvoiceStatus.PartiallyPaid;

        await Db.SaveChangesAsync();
        newPayment = new() { Amount = invoice.TotalAmount - totalPaid };
        StateHasChanged();
    }

    private string GetBadgeClass() => invoice?.Status switch
    {
        InvoiceStatus.Pending => "bg-warning text-dark",
        InvoiceStatus.Paid => "bg-success",
        InvoiceStatus.PartiallyPaid => "bg-info",
        InvoiceStatus.Overdue => "bg-danger",
        _ => "bg-secondary"
    };
}

