@code {
    private Invoice invoice = new() { IssuedDate = DateTime.UtcNow, DueDate = DateTime.UtcNow.AddDays(30) };
    private List<InvoiceItem> items = new() { new InvoiceItem() };
    private List<Owner> owners = new();

    protected override async Task OnInitializedAsync()
    {
        owners = await Db.Owners.OrderBy(o => o.LastName).ToListAsync();
    }

    private void AddItem() => items.Add(new InvoiceItem());

    private async Task Save()
    {
        invoice.TotalAmount = items.Sum(i => i.Quantity * i.UnitPrice);
        invoice.Items = items;
        Db.Invoices.Add(invoice);
        await Db.SaveChangesAsync();
        Nav.NavigateTo($"/billing/{invoice.Id}");
    }
}
